using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notebook = new Notebook();
var webSearcher = new WebSearcher();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearcher.SearchWeb),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Agent setup -------------------------------------------------------------

IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI research assistant that searches the web and takes notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information using multiple queries.
        2. Take notes on the key findings using the note-taking tool.
        3. After gathering enough information, retrieve your notes and produce a
           well-structured summary with sections, key points, and source URLs.
        Be thorough — use at least 2-3 different search queries to cover the topic broadly.
        """,
    tools: tools);

agent.ChatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
};

// --- Run ---------------------------------------------------------------------

Console.WriteLine("Research Agent Starting...");
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions { Temperature = 0f, MaxOutputTokens = 4096 });

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine("═══════════════════════════════════════════════════════════");
Console.WriteLine("                    RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════════════════");
Console.WriteLine(response.Text);
Console.WriteLine("═══════════════════════════════════════════════════════════");

if (notebook.Notes.Count > 0)
{
    Console.WriteLine($"\n📝 {notebook.Notes.Count} note(s) were recorded during research.");
}

// --- Tool implementations ----------------------------------------------------

/// <summary>Simulated web search tool that uses DuckDuckGo Instant Answer API.</summary>
sealed class WebSearcher
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information on a query. Returns a list of results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await s_http.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            // Abstract / main answer
            var abstractText = json.GetProperty("AbstractText").GetString();
            var abstractUrl = json.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrEmpty(abstractText))
            {
                results.Add($"**Summary**: {abstractText}\nSource: {abstractUrl}");
            }

            // Related topics
            if (json.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var link = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrEmpty(text))
                    {
                        results.Add($"- {text}\n  URL: {link}");
                    }
                }
            }

            return results.Count > 0
                ? $"Search results for '{query}':\n\n{string.Join("\n\n", results)}"
                : $"No results found for '{query}'. Try a different search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}. Try a different query.";
        }
    }
}

/// <summary>Note-taking tool that stores research findings in memory.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];

    public IReadOnlyList<string> Notes => _notes;

    [Description("Save a research note. Use this to record key findings, facts, or insights discovered during research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes recorded yet.";

        return string.Join("\n\n", _notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

